<div id="hunting-session" data-tick-url="{{ route('characters.hunting-sessions.tick',[$character,$session['session_id']]) }}"><h1 class="fs-3">Cacería conectada</h1><div class="row g-3 mb-3"><div class="col-md-3"><div class="card"><div class="card-body">Estado <strong id="session-status">{{ $session['status'] }}</strong></div></div></div><div class="col-md-3"><div class="card"><div class="card-body">Victorias <strong id="victories-count">{{ $session['victories_count'] }}</strong></div></div></div><div class="col-md-3"><div class="card"><div class="card-body">Derrotas <strong id="defeats-count">{{ $session['defeats_count'] }}</strong></div></div></div><div class="col-md-3"><div class="card"><div class="card-body">Empates <strong id="draws-count">{{ $session['draws_count'] }}</strong></div></div></div></div><div class="card mb-3"><div class="card-body"><p>Resultados no ganados consecutivos: <strong id="consecutive-count">{{ $session['consecutive_defeats'] }}</strong></p><p>Siguiente encuentro: <strong id="countdown">{{ $session['seconds_until_next_encounter'] === null ? 'Detenido' : $session['seconds_until_next_encounter'].' s' }}</strong></p><p id="stop-message"></p></div></div><form method="POST" action="{{ route('characters.hunting-sessions.stop',[$character,$session['session_id']]) }}" id="stop-form">@csrf<button class="btn btn-danger" type="submit">Detener cacería</button></form></div>
<script>(function(){const root=document.getElementById('hunting-session');let timer=null,inFlight=false,lastState=@json($session);const token=document.querySelector('#stop-form input[name="_token"]').value;function clear(){if(timer!==null){clearTimeout(timer);timer=null;}}function delayFor(s){if(s.status==='stopped')return null;const n=s.seconds_until_next_encounter;if(n===null)return 10000;if(n<=0)return 250;return Math.max(250,Math.min(10000,n*1000));}function render(s){lastState=s;['status','victories_count','defeats_count','draws_count','consecutive_defeats'].forEach(function(k){const id=k==='status'?'session-status':k.replaceAll('_','-');const e=document.getElementById(id);if(e)e.textContent=s[k];});document.getElementById('countdown').textContent=s.seconds_until_next_encounter===null?'Detenido':s.seconds_until_next_encounter+' s';if(s.stop_reason==='consecutive_defeats')document.getElementById('stop-message').textContent='La cacería se detuvo después de 3 encuentros no ganados consecutivos. Mejora tu equipamiento o continúa entrenando en una zona anterior.';if(s.stop_reason==='heartbeat_timeout')document.getElementById('stop-message').textContent='La cacería se detuvo por pérdida de conexión.';if(s.status==='stopped')document.querySelector('#stop-form button').disabled=true;}function schedule(ms){clear();if(ms!==null)timer=setTimeout(tick,ms);}async function tick(){if(inFlight)return;inFlight=true;clear();try{const r=await fetch(root.dataset.tickUrl,{method:'POST',headers:{'X-CSRF-TOKEN':token,'Accept':'application/json','X-Requested-With':'XMLHttpRequest'}});if(!r.ok)throw new Error();const s=await r.json();render(s);schedule(delayFor(s));}catch(e){schedule(5000);}finally{inFlight=false;}}render(lastState);schedule(lastState.status==='running'?250:null);})();</script>
@endsection
